sql:
SELECT name
FROM passengers
WHERE has_family_on_board = 1;

SELECT u.username, al.action_type, al.resource_accessed
FROM users u
INNER JOIN access_logs al ON u.user_id = al.user_id;

external_knowledge:
- 'prime of their life' refers to passengers aged between 20 and 40;
- 'single companion' refers to having just one sibling or spouse aboard;
- 'southern gateway' refers to Southampton (port ID 2);
- 'not chosen the path of luxury' means not in the 1st class.

sql:
SELECT passengers.name, passenger_classes.class_name
FROM passengers
JOIN passenger_classes ON passengers.pclass = passenger_classes.class_id;

SELECT passenger_id, name, survived
FROM passengers
WHERE pclass = 2 AND embarked = 2 AND survived = 1;

SELECT class_id, total_passengers, total_survivors, survival_rate, mortality_rate
FROM survival_statistics
ORDER BY survival_rate DESC;

SELECT AVG(fare) AS average_fare
FROM passengers
WHERE survived = 1;
